def _compact_local_text(key: str, words: dict[str, str]) -> str:
    if key.startswith("payments."):
        if "success" in key or "received" in key:
            return words["paid"]
        if "pending" in key:
            return words["oops"]
        return words["pay"]
    if key.startswith("profile."):
        return words["profile"]
    if key.startswith("download."):
        return words["send"]
    if key.startswith("settings."):
        return words["settings"]
    if key.startswith("wallet."):
        if key.endswith("payment_success"):
            return words["paid"]
        if key.endswith("return_button"):
            return words["wallet_return"]
        if key.endswith(("invoice_title", "invoice_description", "invoice_label")):
            return "{amount} " + words["credits"]
        return words["oops"]
    if key.startswith("generation.section_") or key in {
        "generation.text_to_image", "generation.image_to_image", "generation.image_edit",
        "generation.text_to_video", "generation.image_to_video", "generation.reference_to_video",
        "generation.video_edit", "generation.video_extend", "generation.lipsync",
        "generation.motion_control", "generation.avatar", "generation.audio_to_video",
        "generation.video_to_audio", "generation.effects", "generation.all_models",
    }:
        return words["create"]
    if key.startswith("error_ux.missing_image") or key.endswith("waiting_image") or "wait_image" in key:
        return words["image"]
    if key.startswith("error_ux.missing_video") or key.endswith("waiting_video") or "wait_video" in key:
        return words["video"]
    if key.startswith("error_ux.missing_audio") or key.endswith("waiting_audio") or "wait_audio" in key:
        return words["audio"]
    if key.startswith("error_ux.insufficient_balance") or "balance" in key:
        return words["not_enough"]
    if key.startswith("error_ux.") or key.startswith("errors."):
        return words["oops"]
    if key.startswith("generation.flow") or key.startswith("generation.send") or key.startswith("requirements."):
        return words["send"]
    if key.startswith("generation."):
        return words["create"]
    return words["create"]


